mapper.update:
		UPDATE NMCP_CUST_POINT_GIVE_BASE_BAS 
		SET 

                TOT_ACU_POINT = TOT_ACU_POINT + #{point}
                ,TOT_REMAIN_POINT = TOT_REMAIN_POINT + #{point}


                TOT_USE_POINT = TOT_USE_POINT + #{point}
                ,TOT_REMAIN_POINT = TOT_REMAIN_POINT - #{point}


                TOT_EXTINCTION_POINT = TOT_EXTINCTION_POINT + #{point}
                ,TOT_REMAIN_POINT = TOT_REMAIN_POINT - #{point}

			,POINT_SUM_BASE_DATE = to_char(SYSDATE,'yyyymmddhh24miss')
			,AMD_IP = #{cretIp}
			,AMD_DT = SYSDATE
			,AMD_ID = #{cretId}
		WHERE SVC_CNTR_NO = #{svcCntrNo}

mapper.insert:

		    select SQ_POINT_TXN_SEQ.NEXTVAL FROM DUAL

		INSERT INTO NMCP_CUST_POINT_TXN
		(
			POINT_TXN_SEQ
			,POINT_CUST_SEQ
			,POINT_DIV_CD
			,POINT_TRT_CD
			,POINT_GIVE_BASE_SEQ
			,POINT
			,TOT_REMAIN_POINT
			,POINT_USE_POSBL_ST_DATE
			,POINT_USE_POSBL_END_DATE
			,POINT_TXN_RSN_CD
			,POINT_TXN_DTL_RSN_DESC
			,POINT_ALL_GIVE_SEQ
			,USER_POINT_TRT_SEQ
			,REQUEST_KEY
			,POINT_TRT_DT
			,POINT_TRT_MEMO
			,CRET_IP
			,CRET_DT
			,CRET_ID
			, AMD_IP
            , AMD_DT
            , AMD_ID
		)
		VALUES
		(
			#{pointTxnSeq}
			,#{pointCustSeq}
			,#{pointDivCd}
			,#{pointTrtCd}
			,#{pointGiveBaseSeq}
			,#{point}
			,#{remainPoint}
			,to_char(SYSDATE,'yyyymmddhh24miss')


                ,to_char(add_months(SYSDATE,12),'yyyymmddhh24miss')


                ,to_char(SYSDATE,'yyyymmddhh24miss')


                ,to_char(SYSDATE,'yyyymmddhh24miss')


			,#{pointTxnRsnCd}
			,#{pointTxnDtlRsnDesc}
			,#{pointAllGiveSeq}
			,#{userPointTrtSeq}
			,#{requestKey}
			,SYSDATE
			,#{pointTrtMemo}
			,#{cretIp}
			,SYSDATE
			,#{cretId}
			,#{cretIp}
			,SYSDATE
			,#{cretId}
		)

		INSERT INTO NMCP_CUST_POINT_TXN_DTL
		(
			POINT_TXN_DTL_SEQ
			,POINT_TXN_SEQ
			,ACU_POINT_TXN_SEQ
			,REMAIN_POINT
			,USE_POINT
			,CRET_IP
			,CRET_DT
			,CRET_ID
			, AMD_IP
            , AMD_DT
            , AMD_ID
		)
		VALUES
		(
			SQ_POINT_TXN_DTL_SEQ.NEXTVAL
			,#{pointTxnSeq}
			,#{acuPointTxnSeq}
			,#{remainPoint}
			,#{usePoint}
			,#{cretIp}
			,SYSDATE
			,#{cretId}
			,#{cretIp}
			,SYSDATE
			,#{cretId}
		)

mapper.update:
UPDATE
	NMCP_CUST_POINT_ACU_TXN_DTL
SET REMAIN_POINT = REMAIN_POINT - #{remainPoint}
	,AMD_IP = #{cretIp}
	,AMD_DT = SYSDATE
	,AMD_ID = #{cretId}
WHERE 
	POINT_TXN_SEQ = #{pointTxnSeq}

mapper.insert:

		    select SQ_POINT_CUST_SEQ.NEXTVAL FROM DUAL

		INSERT INTO NMCP_CUST_POINT_GIVE_BASE_BAS
		(
			POINT_CUST_SEQ
            , USER_ID
            , SVC_CNTR_NO
            , TOT_ACU_POINT
            , TOT_USE_POINT
