			#{pointCustSeq}
			,#{userId}
			,#{svcCntrNo}
			,#{totAcuPoint}
			,#{totUsePoint}
			,#{totRemainPoint}
			,#{totExtinctionPoint}
			,to_char(SYSDATE,'yyyymmddhh24miss')
			,#{cretIp}
			,SYSDATE
			,#{cretId}
			,#{amdIp}
			,SYSDATE
			,#{amdId}
		)


			SELECT SQ_POINT_TXN_SEQ.NEXTVAL FROM DUAL

		INSERT INTO NMCP_CUST_POINT_TXN (
			POINT_TXN_SEQ
			, POINT_CUST_SEQ
			, POINT_DIV_CD
			, POINT_TRT_CD
			, POINT_GIVE_BASE_SEQ
			, POINT
			, TOT_REMAIN_POINT
			, POINT_USE_POSBL_ST_DATE
			, POINT_USE_POSBL_END_DATE
			, POINT_TXN_RSN_CD
			, POINT_TXN_DTL_RSN_DESC
			, POINT_ALL_GIVE_SEQ
			, USER_POINT_TRT_SEQ
			, REQUEST_KEY
			, POINT_TRT_DT
			, POINT_TRT_MEMO
			, CRET_IP
			, CRET_DT
			, CRET_ID
			, AMD_IP
			, AMD_DT
			, AMD_ID
		)
		VALUES
			(
			  #{pointTxnSeq}
			, #{pointCustSeq}
			, #{pointDivCd} 
			, #{pointTrtCd}
			, #{pointGiveBaseSeq}
			, #{point}			


                 , (SELECT TOT_REMAIN_POINT - #{totRemainPoint} FROM NMCP_CUST_POINT_GIVE_BASE_BAS WHERE POINT_CUST_SEQ = #{pointCustSeq}) 


                 , (SELECT TOT_REMAIN_POINT + #{totRemainPoint} FROM NMCP_CUST_POINT_GIVE_BASE_BAS WHERE POINT_CUST_SEQ = #{pointCustSeq}) 


			, #{pointUsePosblStDate}
			, #{pointUsePosblEndDate}
			, #{pointTxnRsnCd}
			, #{pointTxnDtlRsnDesc}
			, #{pointAllGiveSeq}
			, #{userPointTrtSeq}
			, #{requestKey}
			, SYSDATE
			, #{pointTrtMemo}
			, #{cretIp}
			, SYSDATE
			, #{cretId}
			, #{cretIp}
			, SYSDATE
			, #{cretId}
		)


			SELECT SQ_POINT_TXN_SEQ.CURRVAL FROM DUAL

		INSERT INTO NMCP_CUST_POINT_ACU_TXN_DTL
		(
			POINT_TXN_SEQ
            ,REMAIN_POINT
			,CRET_IP
			,CRET_DT
			,CRET_ID
			,AMD_IP
            ,AMD_DT
            ,AMD_ID
		)
		VALUES
		(
			#{pointTxnSeq}
			,#{remainPoint}
			,#{cretIp}
			,SYSDATE
			,#{cretId}
			,#{amdIp}
			,SYSDATE
			,#{amdId}
		)


			SELECT SQ_CUST_POINT_GIVE_TGT_SEQ.NEXTVAL FROM DUAL

