			,PSTNG_START_DATE = #{pstngStartDate}
			,PSTNG_END_DATE = #{pstngEndDate}
			,USER_ID = #{userId}
			,REAL_COUPN_NO = #{realCoupnNo}
			,SVC_CNTR_NO = #{svcCntrNo}
			,AMD_IP = #{cretIp}
			,AMD_DT = SYSDATE
			,AMD_ID	 = #{cretId}
		where COUPN_NO = #{coupnNo}
